namespace sv_d84e0010caa44184b0e88ad64851210f.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for this circuit.
/// Every interactive component in the circuit shares the same instance.
/// </summary>
public class WarehouseState
{
    public string CurrentWarehouseId { get; private set; } = "WH-1";
    public string CurrentWarehouseName => Warehouses.TryGetValue(CurrentWarehouseId, out var name) ? name : CurrentWarehouseId;

    public static readonly Dictionary<string, string> Warehouses = new()
    {
        ["WH-1"] = "Warehouse A — East",
        ["WH-2"] = "Warehouse B — West",
        ["WH-3"] = "Warehouse C — Central"
    };

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (CurrentWarehouseId == warehouseId) return;
        CurrentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_d84e0010caa44184b0e88ad64851210f.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts for the current warehouse.
/// Polling is started/stopped by the dashboard page, but the change event
/// notifies ALL subscribers (sidebar badge, dashboard, etc.).
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LowStockCount { get; private set; }

    public event Action? OnChange;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query for items below minimum stock levels.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Increment the polling subscriber count. Starts polling when the first
    /// subscriber arrives.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Decrement the polling subscriber count. Stops polling when no subscribers remain.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            CancelPolling();
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct))
                    break;
                await RefreshAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task RefreshAsync()
    {
        LowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnChange?.Invoke();
    }

    private void CancelPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        CancelPolling();
    }
}

