@page "/dashboard"
@rendermode InteractiveServer
@inject sv_d84e0010caa44184b0e88ad64851210f.Services.WarehouseState WarehouseState
@inject sv_d84e0010caa44184b0e88ad64851210f.Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            @if (AlertService.LowStockCount > 0)
            {
                <span class="badge bg-danger fs-6">@AlertService.LowStockCount items</span>
            }
            else
            {
                <span class="badge bg-success fs-6">None</span>
            }
        </p>
        <p class="text-muted small mb-0">Refreshes every 10 seconds while this page is open.</p>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnChange += _alertHandler;

        // Start polling when the dashboard becomes visible.
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        // Stop polling when the user leaves the dashboard.
        AlertService.StopPolling();

        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnChange -= _alertHandler;
    }
}

